// ─── Helpers ─────────────────────────────────────────────────────────

fn engine_with_mode(mode: Mode) -> Engine {
    std::env::set_var("TWERK_DATASTORE_TYPE", "inmemory");
    std::env::set_var("TWERK_BROKER_TYPE", "inmemory");
    Engine::new(Config {
        mode,
        ..Default::default()
    })
}

fn to_job_id(value: impl Into<String>) -> JobId {
    JobId::new(value).expect("test job id should be valid")
}

fn make_job(id: &str) -> Job {
    Job {
        id: Some(to_job_id(id)),
        state: JobState::Pending,
        tasks: Some(vec![Task {
            name: Some("bdd-task".to_string()),
            image: Some("alpine".to_string()),
            run: Some("echo bdd".to_string()),
            ..Default::default()
        }]),
        task_count: 1,
        ..Default::default()
    }
}

