// --- Claim: State defaults to Idle ---
#[test]
fn state_default_is_idle() {
    assert_eq!(State::default(), State::Idle);
}

// --- Claim: Mode defaults to Standalone ---
#[test]
fn mode_default_is_standalone() {
    assert_eq!(Mode::default(), Mode::Standalone);
}

// --- Claim: Only Terminated is terminal ---
#[test]
fn only_terminated_is_terminal() {
    assert!(!State::Idle.is_terminal());
    assert!(!State::Running.is_terminal());
    assert!(!State::Terminating.is_terminal());
    assert!(State::Terminated.is_terminal());
}

// --- Claim: Idle can transition to any state ---
#[test]
fn idle_can_transition_to_any_state() {
    assert!(State::Idle.can_transition_to(State::Idle));
    assert!(State::Idle.can_transition_to(State::Running));
    assert!(State::Idle.can_transition_to(State::Terminating));
    assert!(State::Idle.can_transition_to(State::Terminated));
}

// --- Claim: Running can only transition to Terminating ---
#[test]
fn running_can_only_transition_to_terminating() {
    assert!(State::Running.can_transition_to(State::Terminating));
    assert!(!State::Running.can_transition_to(State::Idle));
    assert!(!State::Running.can_transition_to(State::Running));
    assert!(!State::Running.can_transition_to(State::Terminated));
}

// --- Claim: Terminating can only transition to Terminated ---
#[test]
fn terminating_can_only_transition_to_terminated() {
    assert!(State::Terminating.can_transition_to(State::Terminated));
    assert!(!State::Terminating.can_transition_to(State::Idle));
    assert!(!State::Terminating.can_transition_to(State::Running));
    assert!(!State::Terminating.can_transition_to(State::Terminating));
}

// --- Claim: Terminated cannot transition to anything ---
#[test]
fn terminated_cannot_transition() {
    assert!(!State::Terminated.can_transition_to(State::Idle));
    assert!(!State::Terminated.can_transition_to(State::Running));
    assert!(!State::Terminated.can_transition_to(State::Terminating));
    assert!(!State::Terminated.can_transition_to(State::Terminated));
}

// --- Claim: Full lifecycle Idle -> Running -> Terminating -> Terminated ---
#[tokio::test]
async fn full_state_lifecycle() {
    let mut engine = engine_with_mode(Mode::Standalone);
    assert_eq!(engine.state(), State::Idle);

    engine.start().await.unwrap();
    assert_eq!(engine.state(), State::Running);

    engine.terminate().await.unwrap();
    assert_eq!(engine.state(), State::Terminated);
    // Verify terminal
    assert!(engine.state().is_terminal());
}

