// --- Claim: MiddlewareComposer applies task middleware in LIFO order ---
#[tokio::test]
async fn middleware_composer_applies_task_middleware_lifo() {
    let call_order: Arc<std::sync::Mutex<Vec<usize>>> = Arc::new(std::sync::Mutex::new(Vec::new()));

    let mw1: twerk_app::engine::TaskMiddlewareFunc = {
        let order = call_order.clone();
        Arc::new(move |handler: twerk_app::engine::TaskHandlerFunc| {
            let order = order.clone();
            let composed: twerk_app::engine::TaskHandlerFunc = Arc::new(move |ctx, et, task| {
                order.lock().unwrap().push(1);
                handler(ctx, et, task)
            });
            composed
        })
    };

    let mw2: twerk_app::engine::TaskMiddlewareFunc = {
        let order = call_order.clone();
        Arc::new(move |handler: twerk_app::engine::TaskHandlerFunc| {
            let order = order.clone();
            let composed: twerk_app::engine::TaskHandlerFunc = Arc::new(move |ctx, et, task| {
                order.lock().unwrap().push(2);
                handler(ctx, et, task)
            });
            composed
        })
    };

    let base_handler: twerk_app::engine::TaskHandlerFunc = Arc::new(|_ctx, _et, _task| Ok(()));

    let composer = MiddlewareComposer::new().with_task(mw1).with_task(mw2);

    let composed = composer.compose_task_handler(base_handler);
    let mut task = Task::default();
    composed(Arc::new(()), TaskEventType::Started, &mut task).unwrap();

    let order = call_order.lock().unwrap();
    // rev().fold means mw2 applied first (wrapping base), then mw1 (wrapping mw2+base)
    // So execution: mw1 → mw2 → base
    assert_eq!(order[0], 1);
    assert_eq!(order[1], 2);
}

// --- Claim: MiddlewareComposer with no middleware returns handler unchanged ---
#[tokio::test]
async fn middleware_composer_identity() {
    let call_count = Arc::new(AtomicUsize::new(0));
    let handler: twerk_app::engine::TaskHandlerFunc = {
        let count = call_count.clone();
        Arc::new(move |_ctx, _et, _task| {
            count.fetch_add(1, Ordering::SeqCst);
            Ok(())
        })
    };

    let composer = MiddlewareComposer::new();
    let composed = composer.compose_task_handler(handler);
    let mut task = Task::default();
    composed(Arc::new(()), TaskEventType::Started, &mut task).unwrap();

    assert_eq!(call_count.load(Ordering::SeqCst), 1);
}

