// --- Claim: EndpointRegistry stores and retrieves endpoints ---
#[test]
fn endpoint_registry_stores_and_retrieves() {
    let handler: EndpointHandler = Arc::new(|_p, _b| {
        Box::pin(async { axum::response::Response::new(axum::body::Body::empty()) })
    });
    let mut reg = EndpointRegistry::new();
    reg.register("GET", "/api/test", handler);

    assert!(reg.contains("GET", "/api/test"));
    assert!(!reg.contains("POST", "/api/test"));
    assert!(!reg.contains("GET", "/api/other"));
    assert!(reg.get("GET", "/api/test").is_some());
}

// --- Claim: EndpointRegistry overwrites on duplicate key ---
#[test]
fn endpoint_registry_overwrites_duplicate() {
    let h1: EndpointHandler = Arc::new(|_p, _b| {
        Box::pin(async { axum::response::Response::new(axum::body::Body::empty()) })
    });
    let h2: EndpointHandler = Arc::new(|_p, _b| {
        Box::pin(async { axum::response::Response::new(axum::body::Body::empty()) })
    });
    let mut reg = EndpointRegistry::new();
    reg.register("GET", "/dup", h1);
    reg.register("GET", "/dup", h2);
    assert_eq!(reg.iter().count(), 1);
}

