// --- Claim: HostEnv middleware injects on StateChange->Running ---
#[tokio::test]
async fn hostenv_middleware_injects_on_statechange_running() {
    std::env::set_var("TWERK_BDD_TEST_VAR", "test-value");
    let hostenv = HostEnv::new(&["TWERK_BDD_TEST_VAR".to_string()]).unwrap();
    let mw = hostenv.middleware();

    let base: twerk_app::engine::TaskHandlerFunc = Arc::new(|_ctx, _et, _task| Ok(()));
    let composed = mw(base);

    let mut task = Task {
        state: TaskState::Running,
        ..Default::default()
    };
    composed(Arc::new(()), TaskEventType::StateChange, &mut task).unwrap();

    let env = task.env.as_ref().unwrap();
    assert_eq!(
        env.get("TWERK_BDD_TEST_VAR"),
        Some(&"test-value".to_string())
    );

    std::env::remove_var("TWERK_BDD_TEST_VAR");
}

// --- Claim: HostEnv middleware does NOT inject on non-Running state ---
#[tokio::test]
async fn hostenv_middleware_skips_non_running_state() {
    std::env::set_var("TWERK_BDD_SKIP_VAR", "should-not-appear");
    let hostenv = HostEnv::new(&["TWERK_BDD_SKIP_VAR".to_string()]).unwrap();
    let mw = hostenv.middleware();

    let base: twerk_app::engine::TaskHandlerFunc = Arc::new(|_ctx, _et, _task| Ok(()));
    let composed = mw(base);

    let mut task = Task {
        state: TaskState::Pending,
        ..Default::default()
    };
    composed(Arc::new(()), TaskEventType::StateChange, &mut task).unwrap();

    assert!(task.env.is_none());
    std::env::remove_var("TWERK_BDD_SKIP_VAR");
}

