// SECTION 19: JOB LISTENER CONTRACTS
// ═══════════════════════════════════════════════════════════════════

// --- Claim: Job listeners can be added to engine ---
// NOTE: add_job_listener uses blocking_write(), so cannot be called from
// within a tokio runtime. This is a BREAKAGE CHECK finding: the public API
// is incompatible with async contexts.
#[test]
fn job_listeners_can_be_added_outside_runtime() {
    let counter = Arc::new(AtomicUsize::new(0));
    let listener: JobListener = {
        let c = counter.clone();
        Arc::new(move |_job| {
            c.fetch_add(1, Ordering::SeqCst);
        })
    };

    let engine = Engine::default();
    engine.add_job_listener(listener);
    // Listener registered without panic
    assert_eq!(counter.load(Ordering::SeqCst), 0); // not invoked yet
}

