// --- Claim: Engine endpoint registration uses "METHOD path" key format ---
#[test]
fn engine_endpoint_key_format() {
    let handler: EndpointHandler = Arc::new(|_p, _b| {
        Box::pin(async { axum::response::Response::new(axum::body::Body::empty()) })
    });
    let mut reg = EndpointRegistry::new();
    reg.register("POST", "/api/jobs", handler);
    assert!(reg.contains("POST", "/api/jobs"));
    assert!(!reg.contains("GET", "/api/jobs"));
}

